### 13. **What is the difference between Models and Entities in Clean Architecture?**

**Entities** (Domain Layer) represent pure business objects, while **Models** (Data Layer) are data transfer objects that handle serialization.

**Comparison:**

| Aspect | Entity (Domain) | Model (Data) |
|--------|----------------|--------------|
| **Location** | domain/entities/ | data/models/ |
| **Purpose** | Business logic | Data transfer & serialization |
| **Dependencies** | None (pure Dart) | May use json_annotation, Hive, etc. |
| **Serialization** | No | Yes (toJson/fromJson) |
| **Mutability** | Usually immutable | Usually immutable |
| **Business Logic** | Yes | No |

**Example:**

**Entity (Domain Layer):**
```dart
// domain/entities/user.dart
class User {
  final String id;
  final String name;
  final String email;
  final DateTime dateOfBirth;
  final UserRole role;
  final bool isActive;

  const User({
    required this.id,
    required this.name,
    required this.email,
    required this.dateOfBirth,
    required this.role,
    required this.isActive,
  });

  // Business logic methods
  int get age {
    final now = DateTime.now();
    int age = now.year - dateOfBirth.year;
    if (now.month < dateOfBirth.month ||
        (now.month == dateOfBirth.month && now.day < dateOfBirth.day)) {
      age--;
    }
    return age;
  }

  bool get isAdult => age >= 18;

  bool get canAccessAdminPanel => role == UserRole.admin && isActive;

  bool get canMakePurchase => isActive && isAdult;

  User copyWith({
    String? name,
    String? email,
    bool? isActive,
    UserRole? role,
  }) {
    return User(
      id: id,
      name: name ?? this.name,
      email: email ?? this.email,
      dateOfBirth: dateOfBirth,
      role: role ?? this.role,
      isActive: isActive ?? this.isActive,
    );
  }

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is User &&
          runtimeType == other.runtimeType &&
          id == other.id;

  @override
  int get hashCode => id.hashCode;
}

enum UserRole {
  user,
  admin,
  moderator,
}
```

**Model (Data Layer):**
```dart
// data/models/user_model.dart
import 'package:json_annotation/json_annotation.dart';
import '../../domain/entities/user.dart';

part 'user_model.g.dart';

@JsonSerializable()
class UserModel extends User {
  // Additional fields for API response that we don't need in domain
  @JsonKey(name: 'created_at')
  final String? createdAt;

  @JsonKey(name: 'updated_at')
  final String? updatedAt;

  const UserModel({
    required super.id,
    required super.name,
    required super.email,
    required super.dateOfBirth,
    required super.role,
    required super.isActive,
    this.createdAt,
    this.updatedAt,
  });

  // Factory constructor for JSON deserialization
  factory UserModel.fromJson(Map<String, dynamic> json) {
    return UserModel(
      id: json['id'] as String,
      name: json['name'] as String,
      email: json['email'] as String,
      dateOfBirth: DateTime.parse(json['date_of_birth'] as String),
      role: _roleFromString(json['role'] as String),
      isActive: json['is_active'] as bool? ?? true,
      createdAt: json['created_at'] as String?,
      updatedAt: json['updated_at'] as String?,
    );
  }

  // JSON serialization
  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'email': email,
      'date_of_birth': dateOfBirth.toIso8601String(),
      'role': _roleToString(role),
      'is_active': isActive,
      if (createdAt != null) 'created_at': createdAt,
      if (updatedAt != null) 'updated_at': updatedAt,
    };
  }

  // Convert from Entity to Model (for sending to API)
  factory UserModel.fromEntity(User user) {
    return UserModel(
      id: user.id,
      name: user.name,
      email: user.email,
      dateOfBirth: user.dateOfBirth,
      role: user.role,
      isActive: user.isActive,
    );
  }

  // Convert to Entity (already done by inheritance)
  User toEntity() => this;

  // Helper methods for enum conversion
  static UserRole _roleFromString(String role) {
    switch (role.toLowerCase()) {
      case 'admin':
        return UserRole.admin;
      case 'moderator':
        return UserRole.moderator;
      default:
        return UserRole.user;
    }
  }

  static String _roleToString(UserRole role) {
    switch (role) {
      case UserRole.admin:
        return 'admin';
      case UserRole.moderator:
        return 'moderator';
      case UserRole.user:
        return 'user';
    }
  }

  // Hive adapter for local storage
  factory UserModel.fromHive(Map<dynamic, dynamic> map) {
    return UserModel(
      id: map['id'] as String,
      name: map['name'] as String,
      email: map['email'] as String,
      dateOfBirth: DateTime.parse(map['date_of_birth'] as String),
      role: _roleFromString(map['role'] as String),
      isActive: map['is_active'] as bool,
    );
  }

  Map<String, dynamic> toHive() {
    return {
      'id': id,
      'name': name,
      'email': email,
      'date_of_birth': dateOfBirth.toIso8601String(),
      'role': _roleToString(role),
      'is_active': isActive,
    };
  }
}
